#include "sda_metrics.h"
void sda_metrics_init(sda_metrics*m,mpfr_prec_t p){ mpfr_inits2(p,m->max_scaled_error,m->max_absolute_error,m->l1_error,m->sd_support,m->sd_infinite,m->tail_mass,m->renyi,m->renyi_minus_one,(mpfr_ptr)0); m->renyi_infinite=0; }
void sda_metrics_clear(sda_metrics*m){ mpfr_clears(m->max_scaled_error,m->max_absolute_error,m->l1_error,m->sd_support,m->sd_infinite,m->tail_mass,m->renyi,m->renyi_minus_one,(mpfr_ptr)0); }
int sda_compute_metrics(mpfr_t*a,size_t n,const sda_u128*p,sda_u128 q,long ro,sda_metrics*m){ mpfr_prec_t pr=mpfr_get_prec(a[0]); mpfr_t qq,pp,d,term,maxlog,sumexp; mpfr_inits2(pr,qq,pp,d,term,maxlog,sumexp,(mpfr_ptr)0); mpfr_set_ui_2exp(qq,(unsigned long)(q>>64),64,MPFR_RNDN); mpfr_add_ui(qq,qq,(unsigned long)q,MPFR_RNDN); mpfr_set_zero(m->l1_error,0); mpfr_set_zero(m->max_absolute_error,0); mpfr_set_zero(m->max_scaled_error,0); for(size_t i=0;i<n;i++){ mpfr_set_ui_2exp(pp,(unsigned long)(p[i]>>64),64,MPFR_RNDN); mpfr_add_ui(pp,pp,(unsigned long)p[i],MPFR_RNDN); mpfr_div(pp,pp,qq,MPFR_RNDN); mpfr_sub(d,a[i],pp,MPFR_RNDN); mpfr_abs(d,d,MPFR_RNDN); mpfr_add(m->l1_error,m->l1_error,d,MPFR_RNDN); if(mpfr_cmp(d,m->max_absolute_error)>0) mpfr_set(m->max_absolute_error,d,MPFR_RNDN); mpfr_mul(term,d,qq,MPFR_RNDN); if(mpfr_cmp(term,m->max_scaled_error)>0) mpfr_set(m->max_scaled_error,term,MPFR_RNDN); }
 mpfr_div_ui(m->sd_support,m->l1_error,2,MPFR_RNDN); mpfr_set(m->sd_infinite,m->sd_support,MPFR_RNDN); mpfr_set_zero(m->tail_mass,0); mpfr_set_zero(maxlog,0); int first=1; for(size_t i=0;i<n;i++){ if(p[i]==0 && mpfr_sgn(a[i])>0){m->renyi_infinite=1; mpfr_set_inf(m->renyi,1); mpfr_set_inf(m->renyi_minus_one,1); break;} mpfr_set_ui_2exp(pp,(unsigned long)(p[i]>>64),64,MPFR_RNDN); mpfr_add_ui(pp,pp,(unsigned long)p[i],MPFR_RNDN); mpfr_div(pp,pp,qq,MPFR_RNDN); mpfr_log(term,a[i],MPFR_RNDN); mpfr_mul_si(term,term,ro,MPFR_RNDN); mpfr_log(d,pp,MPFR_RNDN); mpfr_mul_si(d,d,ro-1,MPFR_RNDN); mpfr_sub(term,term,d,MPFR_RNDN); if(first||mpfr_cmp(term,maxlog)>0){mpfr_set(maxlog,term,MPFR_RNDN);first=0;} }
 mpfr_set_zero(sumexp,0); if(!m->renyi_infinite){ for(size_t i=0;i<n;i++){ mpfr_set_ui_2exp(pp,(unsigned long)(p[i]>>64),64,MPFR_RNDN); mpfr_add_ui(pp,pp,(unsigned long)p[i],MPFR_RNDN); mpfr_div(pp,pp,qq,MPFR_RNDN); mpfr_log(term,a[i],MPFR_RNDN); mpfr_mul_si(term,term,ro,MPFR_RNDN); mpfr_log(d,pp,MPFR_RNDN); mpfr_mul_si(d,d,ro-1,MPFR_RNDN); mpfr_sub(term,term,d,MPFR_RNDN); mpfr_sub(term,term,maxlog,MPFR_RNDN); mpfr_exp(term,term,MPFR_RNDN); mpfr_add(sumexp,sumexp,term,MPFR_RNDN);} mpfr_log(sumexp,sumexp,MPFR_RNDN); mpfr_add(sumexp,sumexp,maxlog,MPFR_RNDN); mpfr_div_si(sumexp,sumexp,ro-1,MPFR_RNDN); mpfr_exp(m->renyi,sumexp,MPFR_RNDN); mpfr_sub_ui(m->renyi_minus_one,m->renyi,1,MPFR_RNDN);} mpfr_clears(qq,pp,d,term,maxlog,sumexp,(mpfr_ptr)0); return 0; }
